import { useEffect, useState } from 'react';

const phrases = ['Cybersecurity Enthusiast', 'Game Modifier', 'AI Practitioner', 'Digital Marketer', 'MIS Student'];

export default function Hero() {
  const [text, setText] = useState('');
  const [pi, setPi] = useState(0);
  const [ci, setCi] = useState(0);
  const [deleting, setDeleting] = useState(false);

  useEffect(() => {
    const phrase = phrases[pi];
    const timeout = setTimeout(() => {
      if (!deleting) {
        setText(phrase.slice(0, ci + 1));
        if (ci + 1 === phrase.length) {
          setTimeout(() => setDeleting(true), 1600);
          return;
        }
        setCi(c => c + 1);
      } else {
        setText(phrase.slice(0, ci - 1));
        if (ci - 1 === 0) {
          setDeleting(false);
          setPi(p => (p + 1) % phrases.length);
          setCi(0);
          return;
        }
        setCi(c => c - 1);
      }
    }, deleting ? 45 : 90);
    return () => clearTimeout(timeout);
  }, [ci, pi, deleting]);

  return (
    <section id="hero" className="min-h-screen bg-parchment grid md:grid-cols-2 items-center gap-8 px-[5%] relative overflow-hidden">
      {/* Background blobs */}
      <div className="blob-hero w-[520px] h-[520px] bg-amber opacity-10 top-[-80px] right-[-100px]" />
      <div className="blob-hero-2 w-[240px] h-[240px] bg-teal opacity-[0.07] bottom-[-30px] left-[35%]" />

      {/* Left */}
      <div className="relative z-10 pt-24 pb-10 md:pb-0 md:pt-0 animate-[fadeUp_.7s_ease_both]">
        <span className="inline-block text-xs font-semibold tracking-widest uppercase text-amber mb-4">
          MIS Student · Asyut, Egypt
        </span>

        <p className="text-lg text-muted2 mb-1">Hi there, I'm</p>

        <h1 className="font-serif-display text-5xl md:text-7xl leading-[1.05] tracking-tight">
          Kareem<br />
          <em className="text-amber not-italic font-serif-display">Basem.</em>
        </h1>

        {/* Typewriter */}
        <div className="flex items-center gap-2 mt-5 text-muted2 text-sm font-medium">
          <span className="text-amber font-bold">→</span>
          <span className="text-ink font-semibold">{text}</span>
          <span className="text-amber animate-[ping2_1s_step-end_infinite]">|</span>
        </div>

        <p className="mt-4 text-[0.95rem] leading-[1.8] text-muted2 max-w-[420px]">
          A <strong className="text-ink2 font-semibold">4th-year MIS student</strong> passionate about{' '}
          <strong className="text-ink2 font-semibold">Cybersecurity</strong>,{' '}
          <strong className="text-ink2 font-semibold">Game Modding</strong>, and building
          digital experiences that actually matter.
        </p>

        <div className="flex gap-3 flex-wrap mt-7">
          <a href="#projects"
            className="px-6 py-3 bg-ink text-parchment font-semibold text-sm rounded-full transition-all hover:bg-amber hover:-translate-y-1 hover:shadow-[0_8px_24px_rgba(240,165,0,.28)]">
            View My Work
          </a>
          <a href="#contact"
            className="px-6 py-3 border-[1.5px] border-ink/20 text-ink2 font-semibold text-sm rounded-full transition-all hover:border-amber hover:text-amber hover:-translate-y-1">
            Get In Touch
          </a>
        </div>

        {/* Socials */}
        <div className="flex items-center gap-3 mt-7">
          <span className="text-xs uppercase tracking-wider text-muted">Find me</span>
          <a href="https://www.linkedin.com/in/karem-basem" target="_blank" rel="noreferrer"
            className="w-9 h-9 rounded-full border-[1.5px] border-ink/12 flex items-center justify-center text-muted2 transition-all hover:border-amber hover:text-amber hover:-translate-y-0.5">
            <svg className="w-3.5 h-3.5" viewBox="0 0 24 24" fill="currentColor">
              <path d="M16 8a6 6 0 0 1 6 6v7h-4v-7a2 2 0 0 0-4 0v7h-4v-7a6 6 0 0 1 6-6zM2 9h4v12H2z"/>
              <circle cx="4" cy="4" r="2"/>
            </svg>
          </a>
          <a href="https://github.com/Kareem-Basem" target="_blank" rel="noreferrer"
            className="w-9 h-9 rounded-full border-[1.5px] border-ink/12 flex items-center justify-center text-muted2 transition-all hover:border-amber hover:text-amber hover:-translate-y-0.5">
            <svg className="w-3.5 h-3.5" viewBox="0 0 24 24" fill="currentColor">
              <path d="M12 2C6.48 2 2 6.48 2 12c0 4.42 2.87 8.17 6.84 9.5.5.09.68-.22.68-.48v-1.7C6.73 19.9 6.14 18 6.14 18c-.45-1.15-1.1-1.46-1.1-1.46-.9-.62.07-.6.07-.6 1 .07 1.53 1.02 1.53 1.02.89 1.52 2.34 1.08 2.91.83.09-.65.35-1.08.63-1.33-2.22-.25-4.56-1.11-4.56-4.94 0-1.09.39-1.98 1.03-2.68-.1-.25-.45-1.27.1-2.64 0 0 .84-.27 2.75 1.02A9.56 9.56 0 0 1 12 6.8c.85 0 1.7.11 2.5.33 1.91-1.29 2.75-1.02 2.75-1.02.55 1.37.2 2.39.1 2.64.64.7 1.03 1.59 1.03 2.68 0 3.84-2.34 4.69-4.57 4.93.36.31.68.92.68 1.85v2.74c0 .27.18.58.69.48A10.01 10.01 0 0 0 22 12c0-5.52-4.48-10-10-10z"/>
            </svg>
          </a>
        </div>
      </div>

      {/* Right — Avatar */}
      <div className="hidden md:flex flex-col items-center gap-5 relative z-10">
        <div className="relative w-[320px] h-[320px] float">
          <div className="blob-avatar absolute inset-0 bg-gradient-to-br from-amber to-[#ffd166]" />
          <div className="absolute inset-[22px] rounded-full bg-cream2 flex items-center justify-center shadow-inner">
            <span className="font-serif-display text-[4.5rem] italic text-ink2">KB</span>
          </div>
          {/* Badge top */}
          <div className="absolute top-4 -right-4 bg-parchment rounded-2xl px-3 py-2 shadow-[0_8px_32px_rgba(26,26,46,.11)] flex items-center gap-2">
            <span className="w-2 h-2 rounded-full bg-green-500 ping2 block" />
            <div>
              <div className="text-[0.78rem] font-semibold text-ink">Open to Work</div>
              <div className="text-[0.65rem] text-muted">Available now</div>
            </div>
          </div>
          {/* Badge bottom */}
          <div className="absolute bottom-8 -left-6 bg-parchment rounded-2xl px-3 py-2 shadow-[0_8px_32px_rgba(26,26,46,.11)] flex items-center gap-2">
            <span className="font-serif-display text-2xl italic text-teal">15+</span>
            <div className="text-[0.65rem] text-muted leading-tight">Certifications<br/>earned</div>
          </div>
        </div>

        {/* Mini stats */}
        <div className="flex gap-8">
          {[{n:'3.02',l:'GPA',c:'text-teal'},{n:'3',l:'Internships',c:'text-amber'},{n:'4th',l:'Year MIS',c:'text-coral'}].map(s => (
            <div key={s.l} className="text-center">
              <div className={`font-serif-display text-3xl italic ${s.c}`}>{s.n}</div>
              <div className="text-[0.65rem] text-muted uppercase tracking-wider font-semibold mt-0.5">{s.l}</div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
